(function () {
  const toggle = document.querySelector('.mobile-toggle');
  const menu = document.querySelector('.mobile-menu');
  if (toggle && menu) {
    toggle.addEventListener('click', function () {
      menu.classList.toggle('is-open');
    });
  }

  const slides = Array.from(document.querySelectorAll('.hero-slide'));
  const dots = Array.from(document.querySelectorAll('.hero-dot'));
  if (slides.length > 0) {
    let current = 0;
    const showSlide = function (index) {
      current = (index + slides.length) % slides.length;
      slides.forEach(function (slide, slideIndex) {
        slide.classList.toggle('is-active', slideIndex === current);
      });
      dots.forEach(function (dot, dotIndex) {
        dot.classList.toggle('is-active', dotIndex === current);
      });
    };
    dots.forEach(function (dot, index) {
      dot.addEventListener('click', function () {
        showSlide(index);
      });
    });
    window.setInterval(function () {
      showSlide(current + 1);
    }, 5200);
  }

  const filterPanels = Array.from(document.querySelectorAll('.filter-panel'));
  filterPanels.forEach(function (panel) {
    const scope = panel.parentElement || document;
    const input = panel.querySelector('.filter-input');
    const year = panel.querySelector('.filter-year');
    const type = panel.querySelector('.filter-type');
    const region = panel.querySelector('.filter-region');
    const cards = Array.from(scope.querySelectorAll('.movie-card'));
    const apply = function () {
      const keyword = (input && input.value ? input.value : '').trim().toLowerCase();
      const selectedYear = year && year.value ? year.value : '';
      const selectedType = type && type.value ? type.value : '';
      const selectedRegion = region && region.value ? region.value : '';
      cards.forEach(function (card) {
        const text = card.getAttribute('data-search') || '';
        const okKeyword = !keyword || text.indexOf(keyword) !== -1;
        const okYear = !selectedYear || card.getAttribute('data-year') === selectedYear;
        const okType = !selectedType || card.getAttribute('data-type') === selectedType;
        const okRegion = !selectedRegion || card.getAttribute('data-region') === selectedRegion;
        card.classList.toggle('hidden-by-filter', !(okKeyword && okYear && okType && okRegion));
      });
    };
    [input, year, type, region].forEach(function (el) {
      if (el) {
        el.addEventListener('input', apply);
        el.addEventListener('change', apply);
      }
    });
  });

  const searchForm = document.querySelector('.search-box');
  const searchInput = document.querySelector('.search-query');
  const resultWrap = document.querySelector('.search-results');
  const renderSearch = function () {
    if (!resultWrap || !searchInput) {
      return;
    }
    const query = searchInput.value.trim().toLowerCase();
    if (!query) {
      resultWrap.innerHTML = '';
      return;
    }
    const matches = movieSearchIndex.filter(function (item) {
      const text = [item.title, item.region, item.type, item.genre, item.summary, item.category].join(' ').toLowerCase();
      return text.indexOf(query) !== -1;
    }).slice(0, 120);
    resultWrap.innerHTML = matches.map(function (item) {
      return '<article class="movie-card">' +
        '<a class="card-cover" href="' + item.url + '"><img src="' + item.cover + '" alt="' + item.title.replace(/"/g, '&quot;') + '" loading="lazy"><span class="play-chip">▶</span><span class="rating-badge">' + item.rating + '</span></a>' +
        '<div class="card-body"><h3><a href="' + item.url + '">' + item.title + '</a></h3>' +
        '<p class="card-meta"><span>' + item.region + '</span><span>' + item.year + '</span><span>' + item.type + '</span></p>' +
        '<p class="card-desc">' + item.summary + '</p><div class="card-tags"><span class="tag">' + item.category + '</span><span class="tag">' + item.genre + '</span></div></div>' +
        '</article>';
    }).join('');
  };
  if (searchForm && searchInput && resultWrap) {
    const params = new URLSearchParams(window.location.search);
    const initial = params.get('q') || '';
    if (initial) {
      searchInput.value = initial;
      renderSearch();
    }
    searchForm.addEventListener('submit', function (event) {
      event.preventDefault();
      renderSearch();
    });
    searchInput.addEventListener('input', renderSearch);
  }
}());
